# sla_monitor.py — check open tickets and fire alerts
from datetime import datetime, timezone, timedelta
from dataclasses import dataclass
import json

# SLA targets in hours (simplified to business hours for P3/P4)
SLA_FIRST_RESPONSE_HOURS = {"P1": 1, "P2": 4, "P3": 16, "P4": 40}
SLA_RESOLUTION_HOURS     = {"P1": 8, "P2": 48, "P3": 80, "P4": None}

@dataclass
class Ticket:
    id: str
    priority: str
    created_at: datetime
    first_response_at: datetime | None
    resolved_at: datetime | None
    paused: bool = False
    paused_since: datetime | None = None

def elapsed_hours(ticket: Ticket, now: datetime) -> float:
    """Elapsed hours excluding pause periods."""
    elapsed = (now - ticket.created_at).total_seconds() / 3600
    if ticket.paused and ticket.paused_since:
        paused = (now - ticket.paused_since).total_seconds() / 3600
        elapsed -= paused
    return max(elapsed, 0)

def check_sla(ticket: Ticket, alert_fn) -> dict:
    now = datetime.now(timezone.utc)
    result = {"ticket_id": ticket.id, "priority": ticket.priority,
              "response_met": None, "resolution_status": None}

    # Check first-response SLA
    target = SLA_FIRST_RESPONSE_HOURS[ticket.priority]
    if ticket.first_response_at is None:
        spent = elapsed_hours(ticket, now)
        pct = spent / target
        if pct >= 1.0:
            alert_fn(ticket.id, "first_response_BREACH", ticket.priority)
            result["response_met"] = False
        elif pct >= 0.8:
            alert_fn(ticket.id, "first_response_WARNING", ticket.priority)
    else:
        result["response_met"] = True

    # Check resolution SLA
    res_target = SLA_RESOLUTION_HOURS.get(ticket.priority)
    if res_target and ticket.resolved_at is None:
        spent = elapsed_hours(ticket, now)
        pct = spent / res_target
        if pct >= 1.0:
            alert_fn(ticket.id, "resolution_BREACH", ticket.priority)
            result["resolution_status"] = "breached"
        elif pct >= 0.8:
            alert_fn(ticket.id, "resolution_WARNING", ticket.priority)
            result["resolution_status"] = "at_risk"
        else:
            result["resolution_status"] = "on_track"
    return result
